import{_ as n,c as a,o as e,aj as t}from"./chunks/framework.CynFBi0q.js";const h=JSON.parse('{"title":"第4章 Coze 扣子实战：低代码 Agent 全攻略","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-agent-dev/chapter_4.md","filePath":"handbook/ai-agent-dev/chapter_4.md","lastUpdated":1781970092000}'),l={name:"handbook/ai-agent-dev/chapter_4.md"};function p(i,s,r,d,o,b){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="第4章-coze-扣子实战-低代码-agent-全攻略" tabindex="-1">第4章 Coze 扣子实战：低代码 Agent 全攻略 <a class="header-anchor" href="#第4章-coze-扣子实战-低代码-agent-全攻略" aria-label="Permalink to “第4章 Coze 扣子实战：低代码 Agent 全攻略”">​</a></h1><p>你以为零代码做 Agent 就是拖拖拽拽？Coze 告诉你：零代码也能做出比代码还复杂的东西。</p><p>我是怕浪猫，上一章我们玩了 Manus，今天来搞 Coze——国内最完善的 Agent 构建平台。8个实战案例，从内容创作到办公自动化，带你把 Coze 的能力榨干。</p><hr><h2 id="_4-1-coze-生态优势与平台对比" tabindex="-1">4.1 Coze 生态优势与平台对比 <a class="header-anchor" href="#_4-1-coze-生态优势与平台对比" aria-label="Permalink to “4.1 Coze 生态优势与平台对比”">​</a></h2><p><strong>Coze 的核心优势</strong></p><p>Coze（扣子）是字节跳动推出的 Agent 构建平台，在国内有独特的生态优势：</p><ol><li><strong>插件生态最完善</strong>：搜索、图片生成、代码运行、天气查询等开箱即用</li><li><strong>多平台分发</strong>：一键发布到微信、飞书、Discord、Web等</li><li><strong>工作流编排</strong>：可视化搭建复杂逻辑，不需要写代码</li><li><strong>知识库管理</strong>：上传文档自动构建知识库，支持RAG</li><li><strong>国内友好</strong>：无需科学上网，中文体验最好</li></ol><p><strong>Coze vs 其他平台对比</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>Coze</th><th>Dify</th><th>Manus</th><th>腾讯元器</th></tr></thead><tbody><tr><td>代码要求</td><td>零</td><td>低</td><td>零</td><td>零</td></tr><tr><td>插件数量</td><td>最多</td><td>少</td><td>中</td><td>少</td></tr><tr><td>工作流</td><td>支持</td><td>支持</td><td>不支持</td><td>有限</td></tr><tr><td>分发渠道</td><td>最多</td><td>API</td><td>Web</td><td>微信</td></tr><tr><td>自托管</td><td>不支持</td><td>支持</td><td>不支持</td><td>不支持</td></tr><tr><td>适合场景</td><td>内容+分发</td><td>企业知识库</td><td>通用任务</td><td>微信生态</td></tr></tbody></table><blockquote><p>Coze 的杀手锏不是&quot;能做 Agent&quot;，而是&quot;做完 Agent 能一键发到所有平台&quot;。做出来和发出去，差了十万八千里。</p></blockquote><hr><h2 id="_4-2-账号注册与界面认知" tabindex="-1">4.2 账号注册与界面认知 <a class="header-anchor" href="#_4-2-账号注册与界面认知" aria-label="Permalink to “4.2 账号注册与界面认知”">​</a></h2><p><strong>注册流程</strong></p><ol><li>访问 <a href="https://www.coze.cn" target="_blank" rel="noreferrer">https://www.coze.cn</a></li><li>使用手机号或抖音账号登录</li><li>进入工作台，首次使用有引导教程</li></ol><p><strong>界面布局</strong></p><p>Coze 的主界面分为几个核心区域：</p><ol><li><strong>工作台</strong>：管理所有 Bot</li><li><strong>插件市场</strong>：浏览和安装插件</li><li><strong>知识库</strong>：管理文档和数据</li><li><strong>工作流</strong>：创建和编辑工作流</li><li><strong>卡片</strong>：设计 Bot 的交互界面</li></ol><p><strong>创建第一个 Bot 的3个步骤</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th><th>要点</th></tr></thead><tbody><tr><td>1. 创建Bot</td><td>点击&quot;创建Bot&quot;</td><td>命名、选择头像、写简介</td></tr><tr><td>2. 编排逻辑</td><td>配置人设、插件、工作流</td><td>人设决定Bot的性格和能力</td></tr><tr><td>3. 发布上线</td><td>选择发布渠道</td><td>支持预览和调试</td></tr></tbody></table><hr><h2 id="_4-3-实战-热搜雷达智能体" tabindex="-1">4.3 实战：热搜雷达智能体 <a class="header-anchor" href="#_4-3-实战-热搜雷达智能体" aria-label="Permalink to “4.3 实战：热搜雷达智能体”">​</a></h2><p>第一个实战，做一个追踪微博热搜的智能体。这个场景展示了 Coze 的定时任务+搜索插件能力。</p><p><strong>设计思路</strong></p><ol><li>定时搜索微博热搜</li><li>用 AI 分析热搜趋势</li><li>生成热搜日报</li><li>推送给用户</li></ol><p><strong>创建步骤</strong></p><p>步骤1：创建Bot，名称&quot;热搜雷达&quot; 步骤2：配置人设提示词</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个热搜追踪专家。每天定时搜索微博热搜榜，分析热搜趋势，生成简洁的热搜日报。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出格式：</span></span>
<span class="line"><span># 热搜日报 [日期]</span></span>
<span class="line"><span>## Top 10 热搜</span></span>
<span class="line"><span>1. [话题] - [热度] - [分类]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 趋势分析</span></span>
<span class="line"><span>[分析今日热搜的特点和趋势]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 推荐关注</span></span>
<span class="line"><span>[从热搜中筛选3个值得深度了解的话题]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>步骤3：添加插件</p><ul><li>搜索插件：用于搜索微博热搜</li><li>定时任务插件：设定每天早上9点触发</li></ul><p>步骤4：配置定时任务</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>触发时间：每天 09:00</span></span>
<span class="line"><span>执行动作：搜索微博热搜 → AI分析 → 生成日报</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>步骤5：发布到飞书/Discord</p><blockquote><p>定时任务+搜索插件，是最简单但最实用的 Agent 模式。每天自动帮你做信息收集，你只需要看结果。</p></blockquote><hr><h2 id="_4-4-实战-自媒体内容生成" tabindex="-1">4.4 实战：自媒体内容生成 <a class="header-anchor" href="#_4-4-实战-自媒体内容生成" aria-label="Permalink to “4.4 实战：自媒体内容生成”">​</a></h2><p>第二个实战，做一个自媒体内容生成智能体。这个场景展示了 Coze 的工作流编排能力。</p><p><strong>设计思路</strong></p><ol><li>输入一个主题</li><li>自动搜索相关素材</li><li>生成标题、正文、标签</li><li>适配不同平台格式</li></ol><p><strong>工作流编排</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[输入主题] </span></span>
<span class="line"><span>    → [搜索素材] → [AI生成初稿] </span></span>
<span class="line"><span>    → [AI润色优化] → [生成多平台版本]</span></span>
<span class="line"><span>    → [输出结果]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个自媒体内容创作专家。根据用户给定的主题，自动完成以下任务：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 搜索相关素材和热点</span></span>
<span class="line"><span>2. 生成3个备选标题（符合平台调性）</span></span>
<span class="line"><span>3. 撰写800-1500字正文</span></span>
<span class="line"><span>4. 生成5-10个标签</span></span>
<span class="line"><span>5. 适配3个平台版本：</span></span>
<span class="line"><span>   - 小红书：加emoji、短段落、口语化</span></span>
<span class="line"><span>   - 公众号：正式、深度、有观点</span></span>
<span class="line"><span>   - 抖音文案：开头3秒钩子、节奏快</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出时标注每个版本的适用平台和字数。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><hr><h2 id="_4-5-实战-小红书内容工厂" tabindex="-1">4.5 实战：小红书内容工厂 <a class="header-anchor" href="#_4-5-实战-小红书内容工厂" aria-label="Permalink to “4.5 实战：小红书内容工厂”">​</a></h2><p>第三个实战，专门针对小红书的内容生产智能体。</p><p><strong>小红书内容的特点</strong></p><ul><li>标题：15字以内，数字+情绪词</li><li>正文：短段落，口语化，emoji点缀</li><li>封面：标题+大字+对比色</li><li>标签：5-10个，包含长尾词</li></ul><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是小红书爆款内容制造机。根据主题生成小红书风格的内容。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>标题公式（任选一种）：</span></span>
<span class="line"><span>- &quot;N个xxx，我靠第X个xxx&quot;</span></span>
<span class="line"><span>- &quot;xxx了N次，终于搞懂了&quot;</span></span>
<span class="line"><span>- &quot;别再xxx了，xxx才对&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>正文规则：</span></span>
<span class="line"><span>- 每段不超过3行</span></span>
<span class="line"><span>- 开头3秒钩子</span></span>
<span class="line"><span>- 中间穿插金句（用引用格式）</span></span>
<span class="line"><span>- 结尾3层CTA（收藏+互动+关注）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>标签：5-8个，包含1个长尾词</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><blockquote><p>小红书的算法推荐本质上是&quot;内容+标签&quot;的匹配游戏。内容决定点击率，标签决定触达率。两个都做好，爆款就是概率问题。</p></blockquote><hr><h2 id="_4-6-实战-新闻网页智能体" tabindex="-1">4.6 实战：新闻网页智能体 <a class="header-anchor" href="#_4-6-实战-新闻网页智能体" aria-label="Permalink to “4.6 实战：新闻网页智能体”">​</a></h2><p>第四个实战，做一个能自动抓取新闻并生成网页的智能体。</p><p><strong>设计思路</strong></p><ol><li>定时抓取指定新闻源</li><li>AI 提取关键信息和摘要</li><li>按分类整理</li><li>生成 HTML 网页</li></ol><p><strong>工作流编排</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[定时触发] → [抓取RSS] → [AI摘要] → [分类整理] → [生成HTML] → [发布]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个工作流的核心是&quot;AI摘要&quot;节点——用 LLM 把每条新闻压缩为3句话，同时提取关键词用于分类。</p><hr><h2 id="_4-7-实战-法律智囊-agent" tabindex="-1">4.7 实战：法律智囊 Agent <a class="header-anchor" href="#_4-7-实战-法律智囊-agent" aria-label="Permalink to “4.7 实战：法律智囊 Agent”">​</a></h2><p>第五个实战，做一个法律咨询智能体。这个场景展示了 Coze 的知识库能力。</p><p><strong>设计思路</strong></p><ol><li>上传法律文档（法规、案例）</li><li>构建法律知识库</li><li>用户提问时，RAG检索相关法律条文</li><li>AI 基于法律条文给出分析</li></ol><p><strong>知识库配置</strong></p><ol><li>上传《民法典》《劳动合同法》《消费者权益保护法》等PDF</li><li>设置切片策略：按法条切片，每条为一个chunk</li><li>检索策略：混合检索（关键词+语义）</li></ol><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个法律咨询助手。根据用户的问题，从知识库中检索相关法律条文，并给出分析。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>注意事项：</span></span>
<span class="line"><span>1. 只基于知识库中的法律条文回答</span></span>
<span class="line"><span>2. 如果知识库中没有相关条文，明确告知</span></span>
<span class="line"><span>3. 给出法律分析时，引用具体法条</span></span>
<span class="line"><span>4. 在回答末尾添加免责声明：&quot;以上内容仅供参考，不构成法律建议。具体问题请咨询专业律师。&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><blockquote><p>法律AI的核心不是&quot;多聪明&quot;，而是&quot;多严谨&quot;。宁可说&quot;我不知道&quot;，也不能编造法条。这个原则适用于所有专业领域的 Agent。</p></blockquote><hr><h2 id="_4-8-实战-多-agent-翻译系统" tabindex="-1">4.8 实战：多 Agent 翻译系统 <a class="header-anchor" href="#_4-8-实战-多-agent-翻译系统" aria-label="Permalink to “4.8 实战：多 Agent 翻译系统”">​</a></h2><p>第六个实战，做一个多 Agent 协作的翻译系统。</p><p><strong>设计思路</strong></p><p>用3个 Agent 协作完成高质量翻译：</p><ol><li><strong>翻译 Agent</strong>：完成初译</li><li><strong>审校 Agent</strong>：检查翻译准确性</li><li><strong>润色 Agent</strong>：优化表达流畅度</li></ol><p><strong>工作流编排</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>[输入原文] → [翻译Agent初译] → [审校Agent检查] → [润色Agent优化] → [输出终稿]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>三个 Agent 的人设</strong></p><p>翻译 Agent：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个专业翻译。将用户输入的内容从[源语言]翻译为[目标语言]。</span></span>
<span class="line"><span>要求：准确、忠实原文、术语统一。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>审校 Agent：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个翻译审校专家。检查翻译稿中的：</span></span>
<span class="line"><span>1. 误译、漏译</span></span>
<span class="line"><span>2. 术语不一致</span></span>
<span class="line"><span>3. 语法错误</span></span>
<span class="line"><span>输出修改建议列表。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>润色 Agent：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个语言润色专家。在保持原意的前提下，优化翻译稿的表达：</span></span>
<span class="line"><span>1. 使语言更地道</span></span>
<span class="line"><span>2. 消除翻译腔</span></span>
<span class="line"><span>3. 提升可读性</span></span>
<span class="line"><span>输出最终版本。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="_4-9-实战-思维导图汇报-agent" tabindex="-1">4.9 实战：思维导图汇报 Agent <a class="header-anchor" href="#_4-9-实战-思维导图汇报-agent" aria-label="Permalink to “4.9 实战：思维导图汇报 Agent”">​</a></h2><p>第七个实战，做一个能把文字内容转为思维导图的智能体。</p><p><strong>设计思路</strong></p><ol><li>用户输入一段文字（会议纪要、学习笔记等）</li><li>AI 提取关键信息，构建层级结构</li><li>生成 Markdown 格式的思维导图</li><li>可导出为 XMind 格式</li></ol><p><strong>人设提示词</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你是一个思维导图生成专家。将用户输入的内容转为结构化的思维导图。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出格式（Markdown）：</span></span>
<span class="line"><span># 中心主题</span></span>
<span class="line"><span>## 分支1</span></span>
<span class="line"><span>### 子节点1-1</span></span>
<span class="line"><span>### 子节点1-2</span></span>
<span class="line"><span>## 分支2</span></span>
<span class="line"><span>### 子节点2-1</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>规则：</span></span>
<span class="line"><span>1. 中心主题1个</span></span>
<span class="line"><span>2. 分支3-7个</span></span>
<span class="line"><span>3. 每个分支下2-5个子节点</span></span>
<span class="line"><span>4. 子节点不超过20字</span></span>
<span class="line"><span>5. 层级不超过3层</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><hr><h2 id="_4-10-实战-飞书数据打通" tabindex="-1">4.10 实战：飞书数据打通 <a class="header-anchor" href="#_4-10-实战-飞书数据打通" aria-label="Permalink to “4.10 实战：飞书数据打通”">​</a></h2><p>第八个实战，做一个能读写飞书多维表格的智能体。</p><p><strong>设计思路</strong></p><ol><li>通过飞书插件连接多维表格</li><li>用户发送指令，Bot 自动读写表格数据</li><li>支持查询、新增、更新操作</li></ol><p><strong>配置步骤</strong></p><ol><li>在 Coze 插件市场搜索&quot;飞书&quot;</li><li>安装飞书多维表格插件</li><li>授权连接到你的飞书工作空间</li><li>选择要操作的多维表格</li><li>配置 Bot 的读写权限</li></ol><p><strong>示例指令</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>查询：今天有哪些待办事项？</span></span>
<span class="line"><span>新增：帮我添加一条待办——周五前完成项目报告</span></span>
<span class="line"><span>更新：把&quot;项目报告&quot;的进度改为80%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="_4-11-工作流与插件高级应用" tabindex="-1">4.11 工作流与插件高级应用 <a class="header-anchor" href="#_4-11-工作流与插件高级应用" aria-label="Permalink to “4.11 工作流与插件高级应用”">​</a></h2><p><strong>工作流编排最佳实践</strong></p><ol><li><strong>先画流程图再编排</strong>：在纸上画出完整流程，再在 Coze 中实现</li><li><strong>每个节点只做一件事</strong>：不要在一个节点里塞太多逻辑</li><li><strong>设置错误处理</strong>：每个节点都要考虑失败情况</li><li><strong>添加日志节点</strong>：在关键步骤后添加日志，方便调试</li><li><strong>版本管理</strong>：每次修改工作流前，先复制一份备份</li></ol><p><strong>插件选择指南</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>推荐插件</th><th>说明</th></tr></thead><tbody><tr><td>搜索</td><td>必应搜索/头条搜索</td><td>国内用头条搜索更稳定</td></tr><tr><td>图片生成</td><td>DALL-E/通义万相</td><td>国内用通义万相更稳定</td></tr><tr><td>代码运行</td><td>代码解释器</td><td>支持Python，适合数据处理</td></tr><tr><td>文件处理</td><td>文档解析</td><td>支持PDF、Word、Excel</td></tr><tr><td>通信</td><td>飞书/邮件</td><td>根据团队使用的工具选择</td></tr></tbody></table><p><strong>5个常见坑和解决方案</strong></p><table tabindex="0"><thead><tr><th>坑</th><th>表现</th><th>解决方案</th></tr></thead><tbody><tr><td>提示词太长</td><td>Bot响应慢，经常截断</td><td>精简提示词，核心规则不超过500字</td></tr><tr><td>插件冲突</td><td>多个插件同时调用出错</td><td>工作流中串行调用，不要并行</td></tr><tr><td>知识库质量差</td><td>RAG回答不准确</td><td>优化文档切片，控制chunk大小在500-1000字</td></tr><tr><td>工作流死循环</td><td>Bot反复调用同一节点</td><td>设置最大循环次数</td></tr><tr><td>分发渠道限制</td><td>微信对AI内容审核严格</td><td>避免敏感词，添加免责声明</td></tr></tbody></table><blockquote><p>Coze 的上限取决于你的想象力，而不是平台能力。80%的人只用到了 Coze 20%的功能。工作流+知识库+多Agent协作，这三个组合起来能做的事远比你想象的多。</p></blockquote><hr><p><strong>本章小结</strong></p><table tabindex="0"><thead><tr><th>实战</th><th>核心能力</th><th>关键技术</th></tr></thead><tbody><tr><td>热搜雷达</td><td>定时任务+搜索</td><td>定时触发+搜索插件</td></tr><tr><td>内容生成</td><td>工作流编排</td><td>多节点串联</td></tr><tr><td>小红书工厂</td><td>平台适配</td><td>提示词模板化</td></tr><tr><td>新闻网页</td><td>数据抓取+生成</td><td>RSS+AI摘要+HTML生成</td></tr><tr><td>法律智囊</td><td>知识库RAG</td><td>文档上传+检索增强</td></tr><tr><td>多Agent翻译</td><td>多Agent协作</td><td>3Agent流水线</td></tr><tr><td>思维导图</td><td>结构化提取</td><td>层级解析+Markdown</td></tr><tr><td>飞书数据</td><td>外部系统集成</td><td>飞书插件+多维表格</td></tr></tbody></table><hr><p>觉得有用？收藏起来，下次直接照抄。</p><p>你用 Coze 做过什么有趣的 Bot？评论区分享你的作品。</p><p>关注怕浪猫，下期我们讲 Dify 实战——RAG 和工作流的企业级应用，5个实战案例带你搭建真正的生产级系统。</p><p>系列进度 4/24</p><p><strong>下章预告：</strong> 第5章我们将深入 Dify 平台，从本地部署到知识库搭建，从日报自动生成到日志分析，5个企业级实战案例帮你掌握 RAG 的核心原理和最佳实践。</p>`,118)])])}const g=n(l,[["render",p]]);export{h as __pageData,g as default};
